import hmac
import hashlib
from fastapi import Header, HTTPException

def hash_key(plaintext: str) -> str:
    return hashlib.sha256(plaintext.encode()).hexdigest()

def verify_api_key(presented: str, stored_hash: str) -> bool:
    return hmac.compare_digest(hash_key(presented), stored_hash)

async def api_key_dep(x_api_key: str = Header(...)):
    key = await db.api_keys.find_by_prefix(x_api_key[:8])
    if not key or not verify_api_key(x_api_key, key.hash):
        raise HTTPException(401, "Invalid API key")
    if key.revoked:
        raise HTTPException(401, "Key revoked")
    return key
